```csharp
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using System.Reflection;

public abstract class BaseRepository<T> : IRepository<T> where T : class
{
    protected readonly DbContext _context;
    protected readonly DbSet<T> _dbSet;

    public BaseRepository(DbContext context)
    {
        _context = context;
        _dbSet = context.Set<T>();
    }

    public virtual async Task<T> GetByIdAsync(object id)
    {
        return await _dbSet.FindAsync(id);
    }

    public virtual async Task<T> FindByDynamicAsync(object id, string propertyName)
    {
        // Get the property info
        PropertyInfo propertyInfo = typeof(T).GetProperty(propertyName);

        if (propertyInfo == null)
        {
            throw new ArgumentException($"Property '{propertyName}' not found in type '{typeof(T).Name}'");
        }

        // Get the value of the property
        object propertyValue = propertyInfo.GetValue(id);

        // Find the entity by the dynamic field
        return await _dbSet.FirstOrDefaultAsync(e => propertyInfo.GetValue(e).Equals(propertyValue));
